import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Hierarchical data structure: Unit -> Topic -> Subtopic
const CURRICULUM = {
  "Unit 1: Building Materials & Construction Practices": {
    "Building Materials": [
      "Brick", "Stones", "Aggregates & M-Sand", "Cement", "Admixtures",
      "Concrete (Self-compacting concrete)", "Mix Design", "Timber",
      "Recycled and modern materials - glass, plastic FRP, ceramic, steel"
    ],
    "Construction Practices": [
      "Masonry", "Construction Equipments", "Building bye-laws",
      "Provisions for fire safety, lighting and ventilation", "Acoustics"
    ]
  },
  "Unit 2: Engineering Survey": {
    "Surveying Fundamentals": [
      "Basics of Surveying", "Chain Surveying", "Compass Surveying", "Plane Table Surveying"
    ],
    "Advanced Surveying": [
      "Levelling", "Computation of area and volume: L.S. and C.S.", "Contouring",
      "Theodolite surveying", "Traversing", "Tacheometry", "Triangulation", "Modern Surveying Techniques"
    ]
  },
  "Unit 3: Engineering Mechanics & Strength of Materials": {
    "Engineering Mechanics": [
      "Forces: Types & Laws", "CoG & MI", "Friction"
    ],
    "Strength of Materials": [
      "Stresses and Strains", "Beams: SFD & BMD", "Theory of simple bending",
      "Deflection of beams", "Torsion", "Combined stresses",
      "Stress Transformations & Failure Theories", "Analysis of plane trusses"
    ]
  },
  "Unit 4: Structural Analysis": {
    "Analysis Methods": [
      "Introduction to Analysis of Structures", "Force/Flexibility Methods of Analysis",
      "Displacement/Stiffness Methods of Analysis", "Matrix method"
    ],
    "Structural Elements": [
      "Arches", "Suspension cables", "Theory of columns",
      "Moving Loads and Influence Lines", "Plastic theory", "Seismic analysis of high rise building"
    ]
  },
  "Unit 5: Geotechnical Engineering": {
    "Soil Mechanics": [
      "Formation & Types of soils", "Physical properties and testing of soils",
      "Classification of Soils for Engineering Practice", "Permeability of Soil",
      "Stress distribution in Soil", "Theory of Consolidation", "Shear strength of Soil",
      "Stability analysis of slope", "Compaction of Soil"
    ],
    "Foundation Engineering": [
      "Shallow foundations", "Pile foundation",
      "Soil exploration & Sampling techniques", "Stabilization of soil",
      "Ground Improvement techniques"
    ]
  },
  "Unit 6: Environmental Engineering": {
    "Water Supply": [
      "Sources & Demand of water", "Hydraulics for conveyance and transmission",
      "Characteristics, analysis of water & water borne diseases", "Functional design of water treatment",
      "Desalination plant", "Water distribution system & Pipe network analysis"
    ],
    "Waste Management": [
      "Planning and design of sewerage system & storm water drain",
      "Sewer appurtenances - Pumping & plumbing system in high rise building",
      "Characteristics and composition of sewage", "Sewage treatment and disposal",
      "Industrial waste water treatment", "Solid waste management",
      "Air and Noise pollution control", "E-Waste management"
    ]
  },
  "Unit 7: RCC / Prestressed Concrete & Steel Structures": {
    "RCC Design": [
      "Working stress design concepts", "Limit state design concepts",
      "Design of Slabs (one way, Two way & Flat slabs)",
      "Design of Beam (singly, doubly reinforced & flanged sections)",
      "Design of Columns & Footings", "Staircase & Lintel",
      "Design of liquid storage structures (elevated and underground)",
      "Design of Retaining wall"
    ],
    "Prestressed & Steel": [
      "Pre-stressing - systems and Methods",
      "Design of Pre-Stressed Members for Flexure & Post tensioning slabs",
      "Design of Bolted and Welded connections", "Design of Tension members",
      "Design of Columns and Bases", "Design of Beams",
      "Design of Plate girder and Gantry girders", "Design of Members of Truss"
    ]
  },
  "Unit 8: Hydraulics & Water Resources": {
    "Fluid Mechanics": [
      "Fluid Properties (Basics)", "Hydrostatic Pressure", "Kinematics of flow",
      "Fluid Dynamics (Applications of Bernoulli & Momentum equation)",
      "Flow through Pipes (Losses)", "Flow measurement in Channel", "Open Channel Flow",
      "Types of Pumps and Characteristics"
    ],
    "Water Resources": [
      "Water resources Planning and Management", "Runoff Estimation",
      "Hydrograph", "Flood Routing", "Flood Control",
      "Soil plant water relationship & Water requirements", "Irrigation Methods",
      "Design of Alluvial Canals", "Design of Head works",
      "Water logging and Land reclamation", "Cross Drainage works"
    ]
  },
  "Unit 9: Urban & Transportation Engineering": {
    "Transportation": [
      "Geometric Design of Highways", "Pavement Materials and Testing",
      "Design, Construction & Maintenance of Roads", "Railway Engineering",
      "Airport Engineering", "Harbour and Docks", "Traffic Engineering"
    ],
    "Urban Planning": [
      "Urbanization and Slum"
    ]
  },
  "Unit 10: Project Management & Estimating": {
    "Management": [
      "Construction Management", "Project Management"
    ],
    "Estimation": [
      "Estimation", "Tender", "Building Valuation"
    ]
  }
};

// Generate unique IDs for curriculum items (same as AIGenerator)
function generateCurriculumIds() {
  const ids = { units: {}, topics: {}, subtopics: {} };
  let unitCounter = 1;
  let topicCounter = 1;
  let subtopicCounter = 1;

  for (const [unitName, topics] of Object.entries(CURRICULUM)) {
    const unitId = `unit_${String(unitCounter).padStart(3, '0')}`;
    ids.units[unitName] = unitId;

    for (const [topicName, subtopics] of Object.entries(topics)) {
      const topicId = `topic_${String(topicCounter).padStart(4, '0')}`;
      ids.topics[`${unitName}|${topicName}`] = topicId;

      for (const subtopicName of subtopics) {
        const subtopicId = `subtopic_${String(subtopicCounter).padStart(5, '0')}`;
        ids.subtopics[`${unitName}|${topicName}|${subtopicName}`] = subtopicId;
        subtopicCounter++;
      }
      topicCounter++;
    }
    unitCounter++;
  }

  return ids;
}

const CURRICULUM_IDS = generateCurriculumIds();

function AddQuestion() {
  const units = Object.keys(CURRICULUM);
  const [unit, setUnit] = useState(units[0]);
  const [topic, setTopic] = useState(Object.keys(CURRICULUM[units[0]])[0]);
  const [subtopic, setSubtopic] = useState(CURRICULUM[units[0]][Object.keys(CURRICULUM[units[0]])[0]][0]);

  const [type, setType] = useState('Theory-based MCQ');
  const [question, setQuestion] = useState('');
  const [questionImage, setQuestionImage] = useState(null);
  const [options, setOptions] = useState({ a: '', b: '', c: '', d: '' });
  const [optionImages, setOptionImages] = useState({ a: null, b: null, c: null, d: null });
  const [correctAnswer, setCorrectAnswer] = useState(0);
  const [explanation, setExplanation] = useState('');
  const [explanationImage, setExplanationImage] = useState(null);
  const [isPublished, setIsPublished] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  // Get topics for selected unit
  const topics = unit ? Object.keys(CURRICULUM[unit]) : [];
  // Get subtopics for selected topic
  const subtopics = unit && topic ? CURRICULUM[unit][topic] : [];

  useEffect(() => {
    if (unit && CURRICULUM[unit]) {
      const newTopics = Object.keys(CURRICULUM[unit]);
      setTopic(newTopics[0]);
      setSubtopic(CURRICULUM[unit][newTopics[0]][0]);
    }
  }, [unit]);

  useEffect(() => {
    if (unit && topic && CURRICULUM[unit][topic]) {
      setSubtopic(CURRICULUM[unit][topic][0]);
    }
  }, [topic]);

  const handleOptionChange = (key, value) => {
    setOptions(prev => ({ ...prev, [key]: value }));
  };

  const handleImageUpload = async (e, type) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    try {
      const response = await axios.post('/api/questions/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const imageUrl = response.data.imageUrl;

      if (type === 'question') {
        setQuestionImage(imageUrl);
      } else if (type === 'explanation') {
        setExplanationImage(imageUrl);
      } else if (['a', 'b', 'c', 'd'].includes(type)) {
        setOptionImages(prev => ({ ...prev, [type]: imageUrl }));
      }
    } catch (error) {
      alert('Image upload failed: ' + error.message);
    }
  };

  const removeImage = (type) => {
    if (type === 'question') {
      setQuestionImage(null);
    } else if (type === 'explanation') {
      setExplanationImage(null);
    } else if (['a', 'b', 'c', 'd'].includes(type)) {
      setOptionImages(prev => ({ ...prev, [type]: null }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      // Get IDs for current selection
      const unitId = CURRICULUM_IDS.units[unit];
      const topicId = CURRICULUM_IDS.topics[`${unit}|${topic}`];
      const subtopicId = CURRICULUM_IDS.subtopics[`${unit}|${topic}|${subtopic}`];

      await axios.post('/api/questions', {
        // Store IDs
        unitId,
        topicId,
        subtopicId,
        // Keep names for reference
        unitName: unit,
        topicName: topic,
        subtopicName: subtopic,
        type,
        question,
        questionImage,
        options,
        optionImages,
        correctAnswer,
        explanation,
        explanationImage,
        is_published: isPublished,
        status: 'pending'
      });

      setMessage('Question saved successfully!');
      // Reset form
      setQuestion('');
      setQuestionImage(null);
      setOptions({ a: '', b: '', c: '', d: '' });
      setOptionImages({ a: null, b: null, c: null, d: null });
      setCorrectAnswer(0);
      setExplanation('');
      setExplanationImage(null);
    } catch (error) {
      setMessage('Error saving question: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const getImagePreview = (imageUrl) => {
    if (!imageUrl) return null;
    return imageUrl.startsWith('http') ? imageUrl : `http://localhost:5000${imageUrl}`;
  };

  return (
    <div className="tab-content">
      <h2>Add Question</h2>

      {message && (
        <div className={message.includes('Error') ? 'error-message' : 'success-message'}>
          {message}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        {/* Hierarchy Selection */}
        <div className="hierarchy-section">
          <h3>Category Hierarchy</h3>
          <div className="form-row three-col">
            <div className="form-group">
              <label>Unit</label>
              <select value={unit} onChange={(e) => setUnit(e.target.value)}>
                {units.map(u => <option key={u} value={u}>{u}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Topic</label>
              <select value={topic} onChange={(e) => setTopic(e.target.value)}>
                {topics.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Subtopic</label>
              <select value={subtopic} onChange={(e) => setSubtopic(e.target.value)}>
                {subtopics.map(st => <option key={st} value={st}>{st}</option>)}
              </select>
            </div>
          </div>
        </div>

        <div className="form-group">
          <label>Question Type</label>
          <select value={type} onChange={(e) => setType(e.target.value)}>
            <option>Theory-based MCQ</option>
            <option>Numerical/Problem-based</option>
            <option>Assertion-Reason</option>
            <option>Match the Following</option>
            <option>Statement type (True/False)</option>
            <option>Diagram-based</option>
          </select>
        </div>

        {/* Question Section */}
        <div className="section">
          <h3>Question</h3>
          <div className="form-group">
            <label>Question Text</label>
            <textarea
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              rows={4}
              required
              placeholder="Enter the question text here..."
            />
          </div>

          <div className="form-group">
            <label>Question Image (Optional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => handleImageUpload(e, 'question')}
            />
            {questionImage && (
              <div className="image-preview-container">
                <img
                  src={getImagePreview(questionImage)}
                  alt="Question"
                  className="image-preview"
                />
                <button type="button" className="btn-remove-image" onClick={() => removeImage('question')}>
                  Remove
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Options Section */}
        <div className="section">
          <h3>Options</h3>
          {['a', 'b', 'c', 'd'].map((opt, idx) => (
            <div key={opt} className="option-row">
              <div className="option-input-group">
                <div className="form-group option-text">
                  <label>Option {opt.toUpperCase()}</label>
                  <input
                    value={options[opt]}
                    onChange={(e) => handleOptionChange(opt, e.target.value)}
                    required
                    placeholder={`Enter option ${opt.toUpperCase()}`}
                  />
                </div>
                <div className="form-group option-image">
                  <label>Image</label>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => handleImageUpload(e, opt)}
                  />
                  {optionImages[opt] && (
                    <div className="image-preview-small">
                      <img
                        src={getImagePreview(optionImages[opt])}
                        alt={`Option ${opt.toUpperCase()}`}
                      />
                      <button type="button" className="btn-remove-small" onClick={() => removeImage(opt)}>
                        x
                      </button>
                    </div>
                  )}
                </div>
                <div className="correct-answer-radio">
                  <input
                    type="radio"
                    name="correctAnswer"
                    id={`correct-${opt}`}
                    checked={correctAnswer === idx}
                    onChange={() => setCorrectAnswer(idx)}
                  />
                  <label htmlFor={`correct-${opt}`}>Correct</label>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Explanation Section */}
        <div className="section">
          <h3>Explanation</h3>
          <div className="form-group">
            <label>Explanation Text</label>
            <textarea
              value={explanation}
              onChange={(e) => setExplanation(e.target.value)}
              rows={4}
              placeholder="Enter the detailed explanation here..."
            />
          </div>

          <div className="form-group">
            <label>Explanation Image (Optional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => handleImageUpload(e, 'explanation')}
            />
            {explanationImage && (
              <div className="image-preview-container">
                <img
                  src={getImagePreview(explanationImage)}
                  alt="Explanation"
                  className="image-preview"
                />
                <button type="button" className="btn-remove-image" onClick={() => removeImage('explanation')}>
                  Remove
                </button>
              </div>
            )}
          </div>
        </div>

        <div className="form-group">
          <label className="checkbox-label">
            <input
              type="checkbox"
              checked={isPublished}
              onChange={(e) => setIsPublished(e.target.checked)}
            />
            Publish to Student Portal
          </label>
        </div>

        <button type="submit" className="btn-primary" disabled={loading}>
          {loading ? 'Saving...' : 'Save Question'}
        </button>
      </form>
    </div>
  );
}

export default AddQuestion;
